+        model: raw.model,
+        steering,
+        allowed_tools: raw.allowed_tools,
+        tap: raw.tap,
+        trace_retain: raw.trace_retain,
+    };
+    let config = GroveConfig {
+        version: 1,
+        mode: Mode::McpLlm,
+        explore: Some(explore_cfg),
